query:
UPDATE articles 
SET excerpt = REPLACE(
  REPLACE(
    REPLACE(
      REPLACE(
        REPLACE(excerpt, 'Best Best Best Best Best ', 'Best '),
        'Best Best Best Best ', 'Best '
      ),
      'Best Best Best ', 'Best '
    ),
    'Best Best ', 'Best '
  ),
  ' - Top Picks & Reviews', ''
)
WHERE excerpt LIKE '%Best Best%' OR excerpt LIKE '%Top Picks & Reviews%';

